def analyze_market_data():
    """Analyse les données de marché pour extraire des patterns"""
    
    print("🔍 ANALYSE DES DONNÉES DE MARCHÉ FIFA")
    print("=" * 80)
    
    matches = market_data_json["Value"]
    
    # Structure pour stocker les analyses
    leagues_analysis = defaultdict(lambda: {
        "count": 0,
        "total_goals_options": set(),
        "handicap_options": set(),
        "over_under_options": set(),
        "score_examples": []
    })
    
    market_type_mapping = {
        1: "Home Win",
        2: "Away Win",
        3: "Draw",
        4: "Away Win",
        5: "Home Win",
        6: "Away Win",
        7: "Handicap Home",
        8: "Handicap Away",
        9: "Total Goals Under",
        10: "Total Goals Over",
        11: "Total Goals Under",
        12: "Total Goals Over",
        13: "Total Goals Under",
        14: "Total Goals Over",
        15: "1X2",
        17: "Total Goals",
        19: "Correct Score",
        62: "Over/Under",
        180: "Asian Handicap",
        181: "Asian Handicap"
    }
    
    for match in matches:
        league = match["L"]
        team_home = match["O1E"]
        team_away = match["O2E"]
        
        leagues_analysis[league]["count"] += 1
        
        # Analyser les événements principaux (E)
        for event in match.get("E", []):
            event_type = event.get("T")
            event_value = event.get("P")
            
            if event_type in [9, 10, 11, 12]:  # Total Goals
                leagues_analysis[league]["total_goals_options"].add(event_value)
            elif event_type in [7, 8]:  # Handicap
                leagues_analysis[league]["handicap_options"].add(event_value)
            elif event_type in [13, 14]:  # Over/Under
                leagues_analysis[league]["over_under_options"].add(event_value)
        
        # Analyser les événements additionnels (AE)
        for ae in match.get("AE", []):
            for market_event in ae.get("ME", []):
                event_type = market_event.get("T")
                event_value = market_event.get("P")
                
                if event_type in [9, 10, 11, 12]:  # Total Goals
                    leagues_analysis[league]["total_goals_options"].add(event_value)
                elif event_type in [7, 8]:  # Handicap
                    leagues_analysis[league]["handicap_options"].add(event_value)
                elif event_type in [13, 14]:  # Over/Under
                    leagues_analysis[league]["over_under_options"].add(event_value)
        
        # Stocker un exemple de score si disponible
        if match.get("SC", {}).get("FS"):
            leagues_analysis[league]["score_examples"].append({
                "home": match["SC"]["FS"].get("S1"),
                "away": match["SC"]["FS"].get("S2")
            })
    
    # Afficher l'analyse par ligue
    print("\n📊 ANALYSE PAR LIGUE")
    print("=" * 80)
    
    for league, data in leagues_analysis.items():
        print(f"\n🏆 {league}")
        print(f"   Nombre de matchs: {data['count']}")
        print(f"   Options Total Goals: {sorted(data['total_goals_options'])}")
        print(f"   Options Handicap: {sorted([x for x in data['handicap_options'] if x is not None])}")
        print(f"   Options Over/Under: {sorted(data['over_under_options'])}")
        if data['score_examples']:
            print(f"   Exemples de scores: {data['score_examples'][:3]}")
    
    # Analyse globale des types de marchés
    print("\n📈 ANALYSE GLOBALE DES TYPES DE MARCHÉS")
    print("=" * 80)
    
    all_total_goals = set()
    all_handicaps = set()
    all_over_under = set()
    
    for data in leagues_analysis.values():
        all_total_goals.update(data["total_goals_options"])
        all_handicaps.update(data["handicap_options"])
        all_over_under.update(data["over_under_options"])
    
    print(f"\n📊 Total Goals (toutes ligues): {sorted(all_total_goals)}")
    print(f"📊 Handicaps (toutes ligues): {sorted([x for x in all_handicaps if x is not None])}")
    print(f"📊 Over/Under (toutes ligues): {sorted(all_over_under)}")
    
    # Analyse par famille de ligue (basée sur le nom)
    print("\n🎯 ANALYSE PAR FAMILLE DE LIGUE")
    print("=" * 80)
    
    families = {
        "RUSH": [],
        "HIGHSCORE": [],
        "CLASSIC": [],
        "PENALTY": [],
        "CONFERENCE": [],
        "CHAMPIONS": [],
        "WORLD": [],
        "SPAIN": [],
        "ENGLAND": []
    }
    
    for league, data in leagues_analysis.items():
        league_upper = league.upper()
        if "RUSH" in league_upper:
            families["RUSH"].append(league)
        elif "HIGHSCORE" in league_upper or "4x4" in league_upper:
            families["HIGHSCORE"].append(league)
        elif "PENALTY" in league_upper:
            families["PENALTY"].append(league)
        elif "CONFERENCE" in league_upper or "3x3" in league_upper:
            families["CONFERENCE"].append(league)
        elif "CHAMPIONS" in league_upper:
            families["CHAMPIONS"].append(league)
        elif "MONDE" in league_upper or "WORLD" in league_upper:
            families["WORLD"].append(league)
        elif "SPAIN" in league_upper or "ESPA" in league_upper:
            families["SPAIN"].append(league)
        elif "ANGLETERRE" in league_upper or "ENGLAND" in league_upper:
            families["ENGLAND"].append(league)
        else:
            families["CLASSIC"].append(league)
    
    for family, leagues in families.items():
        if leagues:
            print(f"\n🏅 Famille: {family}")
            for league in leagues:
                data = leagues_analysis[league]
                print(f"   - {league}")
                print(f"     Total Goals: {sorted(data['total_goals_options'])}")
                print(f"     Handicaps: {sorted([x for x in data['handicap_options'] if x is not None])}")

if __name__ == "__main__":
    analyze_market_data()
